# Advanced utilities using inheritance from base_utils
from base_utils import Processor

class AdvancedProcessor(Processor):
    factor: int

    def __init__(self, v: int, f: int):
        super().__init__(v)
        self.factor = f

    def compute(self) -> int:
        return self.value * self.factor

def apply_twice(p: Processor) -> int:
    return p.compute() + p.compute()
